<?php $adminTitle='LMS Questions'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ $pdo->prepare('INSERT INTO lms_quiz_questions (quiz_id,question,option_a,option_b,option_c,option_d,correct_option,explanation,sort_order) VALUES (?,?,?,?,?,?,?,?,?)')->execute([(int)$_POST['quiz_id'],trim($_POST['question']),trim($_POST['option_a']),trim($_POST['option_b']),trim($_POST['option_c']),trim($_POST['option_d']),$_POST['correct_option'],trim($_POST['explanation']),(int)$_POST['sort_order']]); header('Location: lms-questions.php'); exit; } $quizzes=$pdo->query('SELECT q.*,c.title course_title FROM lms_quizzes q JOIN lms_courses c ON c.id=q.course_id ORDER BY c.title')->fetchAll(); $rows=$pdo->query('SELECT qq.*,q.title quiz_title,c.title course_title FROM lms_quiz_questions qq JOIN lms_quizzes q ON q.id=qq.quiz_id JOIN lms_courses c ON c.id=q.course_id ORDER BY c.title,qq.sort_order')->fetchAll(); ?><h1>Quiz Questions</h1><form class="glass-card mb-4" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><div class="row g-3"><div class="col-md-8"><select class="form-select" name="quiz_id"><?php foreach($quizzes as $q): ?><option value="<?= (int)$q['id']; ?>"><?= e($q['course_title'].' / '.$q['title']); ?></option><?php endforeach; ?></select></div><div class="col-md-2"><select class="form-select" name="correct_option"><option>A</option><option>B</option><option>C</option><option>D</option></select></div><div class="col-md-2"><input class="form-control" name="sort_order" value="1"></div><div class="col-12"><textarea class="form-control" name="question" placeholder="Question" required></textarea></div><?php foreach(['a','b','c','d'] as $o): ?><div class="col-md-6"><input class="form-control" name="option_<?= $o; ?>" placeholder="Option <?= strtoupper($o); ?>" required></div><?php endforeach; ?><div class="col-12"><input class="form-control" name="explanation" placeholder="Explanation" required></div><div class="col-12"><button class="btn btn-premium">Add Question</button></div></div></form><div class="glass-card"><table class="table table-dark"><tr><th>Course</th><th>Question</th><th>Correct</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['course_title']); ?></td><td><?= e($r['question']); ?></td><td><?= e($r['correct_option']); ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>